export const Utils = {};

(() => {
    "use strict";

    /**
     * Array loop
     *
     * @param elements
     * @param callback
     */
    Utils.each = (elements, callback) => {
        if (typeof elements === 'string') {
            elements = document.querySelectorAll(elements);
        }
        for (let i = 0; i < elements.length; i++) {
            if (typeof callback === 'function') {
                callback(i, elements[i]);
            }
        }
    };

    /**
     * Add class on html element
     *
     * @param element
     * @param className
     */
    Utils.addClass = (element, className) => {
        if (!Utils.hasClass(element, className)) {
            element.className += ' ' + className;
            element.className = element.className.replace(/ +(?= )/g, '').trim();
        }
    };

    /**
     * Check if html element has certain class
     *
     * @param element
     * @param classname
     * @returns {boolean}
     */
    Utils.hasClass = (element, classname) => {
        classname = " " + classname + " ";
        if (!element) {
            return false;
        }
        if ((" " + element.className + " ").replace(/[\n\t]/g, " ").indexOf(" " + classname + " ") > -1) {
            return true;
        }
        return false;
    };

    /**
     * Remove class from html element
     * @param node
     * @param className
     */
    Utils.removeClass = (node, className) => {
        node.className = node.className.replace(
            new RegExp('(^|\\s+)' + className + '(\\s+|$)', 'g'),
            '$1'
        ).replace(/ +(?= )/g, '').trim();
    };

    /**
     * merge to object into new object
     *
     * @param defaults
     * @param options
     * @returns {{}}
     */
    Utils.extend = (defaults, options) => {
        const extended = {};
        let prop;
        for (prop in defaults) {
            if (Object.prototype.hasOwnProperty.call(defaults, prop)) {
                extended[prop] = defaults[prop];
            }
        }
        for (prop in options) {
            if (Object.prototype.hasOwnProperty.call(options, prop)) {
                extended[prop] = options[prop];
            }
        }
        return extended;
    };

    /**
     * http://stackoverflow.com/questions/646611/programmatically-selecting-partial-text-in-an-input-field
     *
     * @param field
     * @param start
     * @param end
     */
    Utils.inputSelectionRange = (field, start, end) => {
        if (field.createTextRange) {
            const selRange = field.createTextRange();
            selRange.collapse(true);
            selRange.moveStart('character', start);
            selRange.moveEnd('character', end);
            selRange.select();
            field.focus();
        } else if (field.setSelectionRange) {
            field.focus();
            field.setSelectionRange(start, end);
        } else if (typeof field.selectionStart !== 'undefined') {
            field.selectionStart = start;
            field.selectionEnd = end;
            field.focus();
        }
    };

    /**
     * Check if element is a children of given element of is the same element.
     *
     * @param child
     * @param parent
     * @returns {boolean}
     */
    Utils.isDescendantOrSelfOf = (child, parent) => {
        if (child == parent) {
            return true;
        }
        let node = child.parentNode;
        while (node !== null) {
            if (node == parent) {
                return true;
            }
            node = node.parentNode;
        }
        return false;
    };

    /**
     *
     * Create div element and append  to to exists element
     *
     * @param className
     * @param $parent
     * @returns {Element}
     */
    Utils.createElementAndAppendIt = (className, $parent, type = 'div') => {
        const element = document.createElement(type);
        element.className = className;
        $parent.appendChild(element);
        return element;
    };

    /**
     *
     * @param string
     * @returns {*}
     */
    Utils.splitBySpace = (string) => {
        return string.match(/(?:[^\s"]+|"[^"]*")+/g);
    };

    /**
     * Check if string starts with certain string
     *
     * @param string
     * @param startsWith
     * @returns {boolean}
     */
    Utils.startsWith = (string, startsWith) => {
        return string.indexOf(startsWith) === 0;
    };

    /**
     * Check if string ends with certain string
     *
     * @param string
     * @param endsWith
     * @returns {boolean}
     */
    Utils.endsWith = (string, endsWith) => {
        return string.indexOf(endsWith, string.length - endsWith.length) !== -1;
    };

    Utils.strRepeat = (str, times) => {
        let output = '';
        for (let i = 0; i < times; i++) {
            output += str;
        }
        return output;
    };

    /**
     * Place the cursor  at the end of a contentEditable
     * @param el
     */
    Utils.placeCaretAtEnd = (el) => {
        el.focus();
        if (typeof window.getSelection != "undefined" && typeof document.createRange != "undefined") {
            const range = document.createRange();
            range.selectNodeContents(el);
            range.collapse(false);
            const sel = window.getSelection();
            sel.removeAllRanges();
            sel.addRange(range);
        } else if (typeof document.body.createTextRange != "undefined") {
            const textRange = document.body.createTextRange();
            textRange.moveToElementText(el);
            textRange.collapse(false);
            textRange.select();
        }
    };

})();

export class CommandPrompt {
    /**
     * 
     * @param commandLine
     * @param title
     * @param confirmCallback
     */
    constructor(commandLine, title, confirmCallback) {
        this.title = title;
        this.confirmCallback = confirmCallback;
        this.commandLine = commandLine;
        this.start();
    }

    /**
     * Start/Restart prompt message
     */
    start() {
        if (this.commandLine.commandRow) {
            this.commandLine.commandRow.disable();
        }
        this.commandLine.commandRow = new CommandRow(this.commandLine, (value) => {
            this.confirmCallback.apply(this, [value]);
        });
        this.commandLine.commandRow.hideUser();
        this.commandLine.commandRow.setProtectedEntry(this.title);
        this.commandLine.commandRow.isolate(true);
    }

    /**
     * Set prompt title
     */
    setTitle(title) {
        this.title = title;
        return this;
    }
}

export class CommandSecret {
    /**
     * 
     * @param commandLine
     * @param title
     * @param confirmCallback
     */
    constructor(commandLine, title, confirmCallback) {
        this.title = title;
        this.confirmCallback = confirmCallback;
        this.commandLine = commandLine;
        this.start();
    }

    /**
     * Replace visible text with Asterisk
     */
    start() {
        if (this.commandLine.commandRow) {
            this.commandLine.commandRow.disable();
        }
        this.commandLine.commandRow = new CommandRow(this.commandLine, (value) => { return value; });
        this.commandLine.commandRow.hideUser();
        this.commandLine.commandRow.setProtectedEntry(this.title);

        this.element = Utils.createElementAndAppendIt('secret', this.commandLine.commandRow.commandRow, 'input');
        this.element.focus();

        this.element.addEventListener('keyup', () => {
            this.commandLine.commandRow.commandEntry.innerHTML = Utils.strRepeat('*', this.element.value.length);
        }, false);

        this.element.addEventListener('keydown', (e) => {
            if (e.keyCode == 13) {
                e.preventDefault();
                const value = this.element.value;
                this.element.parentNode.removeChild(this.element);
                delete this.element;
                this.confirmCallback.apply(this, [value]);
            }
        }, false);

        this.commandLine.commandRow.disable();

        this.commandLine.commandRow.isolate(true);
    }

    /**
     * Set prompt title
     */
    setTitle(title) {
        this.title = title;
        return this;
    }
}

export class CommandRow {
    /**
     *
     * @param commandLine
     * @param onEnterCallback
     */
    constructor(commandLine, onEnterCallback) {
        this.commandLine = commandLine;
        this.container = commandLine.container;

        this.commandRow = Utils.createElementAndAppendIt('command-row active', this.container);

        this.commandTime = Utils.createElementAndAppendIt('command-time', this.commandRow);

        const currentDate = new Date();
        const time = `${currentDate.getHours()}:${currentDate.getMinutes()}:${currentDate.getSeconds()}`;

        this.commandTime.innerHTML = `[${time}]`;

        this.commandUser = Utils.createElementAndAppendIt('command-user', this.commandRow);
        this.commandUser.innerHTML = `${this.commandLine.username}$`;

        this.commandEntryProtected = Utils.createElementAndAppendIt('command-entry command-entry-protected', this.commandRow);

        this.commandEntry = Utils.createElementAndAppendIt('command-entry', this.commandRow);
        this.commandEntry.contentEditable = true;
        this.commandEntry.focus();

        Utils.placeCaretAtEnd(this.commandEntry);

        this.commandEntryKeyDownCallback = (e) => {
            if (e.keyCode == 13) {
                e.preventDefault();
                this.commandEntry.contentEditable = false;
                this.commandEntry.removeEventListener('keydown', this.commandEntryKeyDownCallback);
                onEnterCallback(this.commandEntry.textContent);
                return false;
            }
        };

        this.commandEntry.addEventListener('keydown', this.commandEntryKeyDownCallback);

        this.isolation = false;
    }

    /**
     * Disable command row, remove event listener and content editable
     *
     * @returns {CommandRow}
     */
    disable() {
        this.commandEntry.contentEditable = false;
        Utils.removeClass(this.commandRow, 'active');
        this.commandEntry.removeEventListener('keydown', this.commandEntryKeyDownCallback);
        return this;
    }

    /**
     * Hide user name
     *
     * @returns {CommandRow}
     */
    hideUser() {
        this.commandUser.parentNode.removeChild(this.commandUser);
        return this;
    }

    /**
     * Hide time
     *
     * @returns {CommandRow}
     */
    hideTime() {
        this.commandTime.parentNode.removeChild(this.commandTime);
        return this;
    }

    /**
     * Add content to the editable entry
     *
     * @param message
     * @returns {CommandRow}
     */
    setEntry(message) {
        this.commandEntry.innerHTML = message;
        Utils.placeCaretAtEnd(this.commandEntry);
        return this;
    }

    /**
     * Add content to the protected entry
     *
     * @param message
     * @returns {CommandRow}
     */
    setProtectedEntry(message) {
        this.commandEntryProtected.innerHTML = message;
        return this;
    }

    /**
     * Put this command row in isolation mode
     * Isolation mode will protected the command row from command line events.
     *
     * @param flag
     * @returns {boolean}
     */
    isolate(flag) {
        this.isolation = flag;
        return false;
    }

    /**
     * Check if this command row is in isolated mode
     *
     * @returns {boolean}
     */
    isIsolated() {
        return this.isolation === true;
    }

    /**
     * Get Entry value
     *
     * @returns {string}
     */
    getEntry() {
        return this.commandEntry.textContent;
    }
}

export class CommandInput {
    /**
     *
     * @param name
     * @param value
     * @param required
     * @param isOption
     */
    constructor(name, value, required, isOption) {
        this.name = name;
        this.required = required;
        this.value = value;
        this._isOption = isOption;
    }

    /**
     * Check if this input is an option that starts with two hyphens (--)
     *
     * @returns {boolean}
     */
    isOption() {
        return this._isOption === true;
    }

    /**
     * Check if this command is required value
     *
     * @returns {boolean}
     */
    isRequired() {
        return this.required === true;
    }

    /**
     * Get the input name
     *
     * @returns string
     */
    getName() {
        return this.name;
    }

    /**
     * Get the input value
     *
     * @returns string
     */
    getValue() {
        return this.value;
    }
}

export class CommandResolver {
    /**
     * This object is responsible to resolve a given command and fetch argument and option names
     *
     * @param command
     */
    constructor(command) {
        this.signature = command;

        const commandSegments = Utils.splitBySpace(command);

        this.command = null;
        this.arguments = [];
        this.options = [];

        if (commandSegments.length === 0) {
            throw "Command cannot be empty";
        }

        this.command = commandSegments.shift();

        let parsedInput;

        for (let i = 0; i < commandSegments.length; i++) {
            parsedInput = this.parseInput(commandSegments[i]);
            if (parsedInput.isOption()) {
                this.options.push(parsedInput);
            } else {
                this.arguments.push(parsedInput);
            }
        }
    }

    /**
     * Return command signature
     * 
     * @returns string
     */
    getSignature() {
        return this.signature;
    }

    /**
     * Assign parsedCommand arguments & options values
     * 
     * @param parsedCommand
     */
    dispatch(parsedCommand) {
        const commandSegments = parsedCommand.getCommandSegments();
        const _options = [];
        const _arguments = [];
        let parsedInput;
        for (let i = 0; i < commandSegments.length; i++) {
            parsedInput = this.parseInput(commandSegments[i]);
            if (parsedInput.isOption()) {
                _options.push(parsedInput);
            } else {
                _arguments.push(parsedInput);
            }
        }

        /**
         * Provided arguments exceeds the registered command signature arguments
         * Allow if last argument ends with * (wildcard)
         */
        const hasWildcard = this.arguments.length > 0 && this.arguments[this.arguments.length - 1].getName().endsWith('*');
        if (_arguments.length > this.arguments.length && !hasWildcard) {
            throw [
                this.signature,
                `${this.command} Command arguments not recognized.`
            ];
        }

        /**
         * Some arguments is required
         */
        for (let argumentIndex = 0; argumentIndex < this.arguments.length; argumentIndex++) {
            const isWildcardArg = this.arguments[argumentIndex].getName().endsWith('*');
            
            if (this.arguments[argumentIndex].isRequired() && typeof _arguments[argumentIndex] == 'undefined' && !isWildcardArg) {
                throw [
                    this.signature,
                    `${this.arguments[argumentIndex].getName()} Argument Is required.`
                ];
            }

            /**
             * Assign arguments names and values to the parsed Command arguments
             */
            if (isWildcardArg) {
                // For wildcard, join all remaining arguments
                const remainingArgs = _arguments.slice(argumentIndex);
                const wildcardValue = remainingArgs.length > 0 ? remainingArgs.map(arg => arg.getName()).join(' ') : '';
                parsedCommand.setArgument(this.arguments[argumentIndex].getName().replace('*', ''), wildcardValue);
                break; // Stop processing after wildcard
            } else {
                if (_arguments[argumentIndex]) {
                    parsedCommand.setArgument(this.arguments[argumentIndex].getName(), _arguments[argumentIndex].getName());
                } else {
                    parsedCommand.setArgument(this.arguments[argumentIndex].getName(), this.arguments[argumentIndex].getValue());
                }
            }
        }

        /**
         * Assign options names and values to the parsed Command options
         */
        for (let resolvedOptionIndex = 0; resolvedOptionIndex < this.options.length; resolvedOptionIndex++) {
            parsedCommand.setOption(this.options[resolvedOptionIndex].getName().substring(2), this.options[resolvedOptionIndex].getValue());
        }

        /**
         * Assign options names and values that provided by user to the parsed Command options
         */
        for (let parsedOptionIndex = 0; parsedOptionIndex < _options.length; parsedOptionIndex++) {
            parsedCommand.setOption(_options[parsedOptionIndex].getName().substring(2), _options[parsedOptionIndex].getValue());
        }
    }

    /**
     * Get signature command name
     * 
     * @returns string
     */
    getCommand() {
        return this.command;
    }

    /**
     * Get signature arguments
     *
     * @returns {Array}
     */
    getArguments() {
        return this.arguments;
    }

    /**
     * Get signature option
     *
     * @returns {Array}
     */
    getOptions() {
        return this.options;
    }

    /**
     * Parse given input and instantiate a CommandInput object
     * The may be an argument input or option input
     * 
     * @param input
     * @returns {CommandInput}
     */
    parseInput(input) {
        let required = false;
        let value = null;
        let name;

        const inputSegments = input.split('=');

        const isOption = (Utils.startsWith(input, '--') === true);

        name = inputSegments.shift();

        if (isOption === false && Utils.endsWith(name, '?') !== true) {
            required = true;
        }

        if (isOption === false && Utils.endsWith(name, '?') === true) {
            name = name.slice(0, -1);
        }

        if (inputSegments.length > 0) {
            value = inputSegments.join('');
        }

        if (value && Utils.startsWith(value, '"') === true && Utils.endsWith(value, '"') === true) {
            value = value.slice(1);
            value = value.slice(0, -1);
        }

        return new CommandInput(name, value, required, isOption);
    }
}

export class CommandParser {
    /**
     * This object is responsible to resolve a given command and fetch argument and option values
     * 
     * @param command
     */
    constructor(command) {
        const commandSegments = Utils.splitBySpace(command);

        this.command = null;
        this.arguments = {};
        this.options = {};

        if (commandSegments.length === 0) {
            throw "Command cannot be empty";
        }

        this.command = commandSegments.shift();
        this.commandSegments = commandSegments;
    }

    /**
     * Get command name
     *
     * @returns string
     */
    getCommand() {
        return this.command;
    }

    /**
     * Get argument value
     *
     * @param argument
     * @returns {*}
     */
    getArgument(argument) {
        return this.arguments[argument];
    }

    /**
     * Get option value
     *
     * @param option
     * @returns string
     */
    getOption(option) {
        return this.options[option];
    }

    /**
     * Return command segments without command name in the early parse
     *
     * @returns {*}
     */
    getCommandSegments() {
        return this.commandSegments;
    }

    /**
     * Set new Argument name & value
     *
     * @param name
     * @param value
     * @returns {CommandParser}
     */
    setArgument(name, value) {
        this.arguments[name] = value;
        return this;
    }

    /**
     * Set new Option name & value
     *
     * @param name
     * @param value
     * @returns {CommandParser}
     */
    setOption(name, value) {
        this.options[name] = value;
        return this;
    }
}

export class CommandLine {
    /**
     *
     * @param container
     * @param username
     */
    constructor(container, username = null) {
        this.container = container;
        this.commands = [];
        this.history = [];
        this.currentHistoryIndex = 0;
        this.setUsername(username || "root@localhost");

        this.container.addEventListener('keydown', (e) => {
            if (this.commandRow && this.commandRow.isIsolated() === false) {
                /**
                 * Commands history cursor
                 */
                if ((e.keyCode == 38 || e.keyCode == 40)) {
                    e.preventDefault();
                    if (e.keyCode == 38) {
                        // up .. previous
                        if (this.currentHistoryIndex >= 0) {
                            this.currentHistoryIndex--;
                        }
                    } else if (e.keyCode == 40) {
                        if (this.currentHistoryIndex < this.history.length) {
                            this.currentHistoryIndex++;
                        }
                    }
                    if (typeof this.history[this.currentHistoryIndex] != "undefined") {
                        this.commandRow.setEntry(this.history[this.currentHistoryIndex]);
                    } else {
                        this.commandRow.setEntry('');
                    }
                } else if (e.keyCode == 9) {
                    e.preventDefault();
                    const results = [];
                    const userCommand = this.commandRow.getEntry();
                    if (userCommand === '') {
                        return;
                    }
                    for (let command = 0; command < this.commands.length; command++) {
                        if (Utils.startsWith(this.commands[command].resolved.getCommand(), userCommand)) {
                            results.push(this.commands[command]);
                        }
                    }
                    if (results.length == 1) {
                        this.commandRow.setEntry(results[0].resolved.getCommand());
                    } else if (results.length > 1) {
                        const autocompletionResults = [];
                        for (let resultIndex = 0; resultIndex < results.length; resultIndex++) {
                            autocompletionResults.push(results[resultIndex].resolved.getSignature());
                            autocompletionResults.push(results[resultIndex].description);
                        }
                        this.list(autocompletionResults, 2);
                        this.startNewCommand();
                        this.commandRow.setEntry(userCommand);
                    }
                }
            }
        });

        /**
         * Ctrl + c to Stop Execution &  Ctrl + r to Clear Buffer
         */
        let ctrlDown = false;
        const ctrlKey = 17;
        const cKey = 67;
        const rKey = 82;

        this.container.addEventListener('keydown', (e) => {
            if (e.keyCode == ctrlKey) {
                ctrlDown = true;
            }
        });

        this.container.addEventListener('keyup', (e) => {
            if (e.keyCode == ctrlKey) {
                ctrlDown = false;
            }
        });

        this.container.addEventListener('keydown', (e) => {
            if (ctrlDown && e.keyCode == cKey) {
                this.stop();
            } else if (ctrlDown && e.keyCode == rKey) {
                e.preventDefault();
                this.container.innerHTML = '';
                this.stop();
            }
        });

        this.container.addEventListener('click', () => {
            if (this.commandRow) {
                this.commandRow.commandEntry.focus();
            }
        });
    }

    /**
     * Print new command line input
     */
    startNewCommand() {
        if (this.commandRow) {
            this.commandRow.disable();
        }

        this.commandRow = new CommandRow(this, (value) => {
            if (/\S/.test(value)) {
                this.run(value);
            } else {
                this.stop();
            }
        });
    }

    /**
     * register new command
     *
     * @param command
     * @param callback
     */
    addCommand(command, callback, description = '') {
        this.commands.push({
            name: command,
            callback: callback,
            description: description,
            resolved: new CommandResolver(command)
        });
    }

    /**
     * Run a given command
     *
     * @param command
     */
    run(command) {
        try {
            this.history.push(command);
            this.currentHistoryIndex = this.history.length;
            this.find(command);
        } catch (err) {
            if (err instanceof Array) {
                for (let messageIndex = 0; messageIndex < err.length; messageIndex++) {
                    this.error(err[messageIndex]);
                }
            } else {
                this.error(err);
            }
            this.stop();
        }
    }

    /**
     * Find the registered command object by given command text
     * 
     * @param command
     */
    find(command) {
        const parsedCommand = new CommandParser(command);
        let resolvedCommand;

        for (let i = 0; i < this.commands.length; i++) {
            // Case-insensitive command matching
            if (this.commands[i].resolved.getCommand().toLowerCase() === parsedCommand.getCommand().toLowerCase()) {
                resolvedCommand = this.commands[i].resolved;
                resolvedCommand.dispatch(parsedCommand);
                const result = this.commands[i].callback.apply(this, [parsedCommand]);
                
                // Handle async functions (Promises)
                if (result instanceof Promise) {
                    result.then((resolvedResult) => {
                        if (resolvedResult !== false) {
                            this.stop();
                        }
                    }).catch((error) => {
                        this.error(error);
                        this.stop();
                    });
                } else {
                    if (result !== false) {
                        this.stop();
                    }
                }
                return;
            }
        }

        throw `<b>[${parsedCommand.getCommand()}]</b> Command Not found`;
    }

    /**
     * Output Error message
     * 
     * @param message
     */
    error(message) {
        this.output(message);
        Utils.addClass(this.commandRow.commandRow, 'error');
    }

    /**
     * Output Success message
     *
     * @param message
     */
    success(message) {
        this.output(message);
        Utils.addClass(this.commandRow.commandRow, 'success');
    }

    /**
     * Output Information message
     *
     * @param message
     */
    info(message) {
        this.output(message);
        Utils.addClass(this.commandRow.commandRow, 'info');
    }

    /**
     * Output Warning message
     *
     * @param message
     */
    warning(message) {
        this.output(message);
        Utils.addClass(this.commandRow.commandRow, 'warning');
    }

    /**
     * Output non-styled message
     *
     * @param message
     */
    output(message) {
        this.stop();
        this.commandRow.hideUser();
        this.commandRow.setEntry(message);
        this.commandRow.disable();
    }

    /**
     * Receive user input
     *
     * @param title
     * @param confirmCallback
     */
    prompt(title, confirmCallback) {
        new CommandPrompt(this, title, confirmCallback);
    }

    /**
     * Receive user input
     *
     * @param title
     * @param confirmCallback
     */
    secret(title, confirmCallback) {
        new CommandSecret(this, title, confirmCallback);
    }

    /**
     * Ask user for confirmation by Y or N , y or n
     *
     * @param title
     * @param confirmCallback
     */
    confirm(title, confirmCallback) {
        title += '[Y/N]';
        const confirm = () => {
            this.commandRow = new CommandRow(this, (value) => {
                value = value.toLowerCase();
                if (value !== 'n' && value !== 'y') {
                    this.commandRow.disable();
                    confirm();
                } else {
                    confirmCallback(value === 'y');
                }
            });
            this.commandRow.isolate(true);
            this.commandRow.hideUser();
            this.commandRow.setProtectedEntry(title);
        };
        confirm();
    }

    /**
     * Output data listing
     *
     * @param data
     * @param cellsPerRow
     */
    list(data, cellsPerRow = 4) {
        const arrayChunk = (array, chunk) => {
            const chunks = [];
            for (let i = 0, j = array.length; i < j; i += chunk) {
                chunks.push(array.slice(i, i + chunk));
            }
            return chunks;
        };

        let output = '<table class="command-line-table">';
        const dataChuncks = arrayChunk(data, cellsPerRow);
        for (let row = 0; row < dataChuncks.length; row++) {
            output += '<tr>';
            for (let cell = 0; cell < dataChuncks[row].length; cell++) {
                output += `<td>${dataChuncks[row][cell]}</td>`;
            }
            output += '</tr>';
        }
        output += '</table>';
        this.output(output);
        this.commandRow.hideTime();
        Utils.addClass(this.commandRow.commandEntry, 'block');
    }

    /**
     * Enhanced list with multiple styles
     *
     * @param data
     * @param cellsPerRow
     * @param options - { style: 'table'|'list'|'grid'|'tree', header: [], className: '', highlight: false }
     */
    listEnhanced(data, cellsPerRow = 4, options = {}) {
        const defaultOptions = {
            style: 'table',
            header: null,
            className: '',
            highlight: false,
            ...options
        };

        const arrayChunk = (array, chunk) => {
            const chunks = [];
            for (let i = 0, j = array.length; i < j; i += chunk) {
                chunks.push(array.slice(i, i + chunk));
            }
            return chunks;
        };

        let output = '';
        const styleClass = defaultOptions.className ? ` ${defaultOptions.className}` : '';
        const highlightClass = defaultOptions.highlight ? ' highlight' : '';

        if (defaultOptions.style === 'list' || defaultOptions.style === 'tree') {
            output = '<div class="command-line-list' + styleClass + highlightClass + '">';
            for (let i = 0; i < data.length; i++) {
                let prefix = '';
                let itemContent = data[i];
                let itemClass = 'list-item';
                
                // Check if item is indented (nested item) - starts with whitespace
                const indentMatch = itemContent.match(/^(\s+)(.*)/);
                const isIndented = indentMatch !== null;
                
                if (defaultOptions.style === 'tree') {
                    if (isIndented) {
                        // For nested/indented items, extract content (remove leading spaces)
                        const content = indentMatch[2];
                        // Add nested class and use padding for indentation
                        itemClass += ' nested-item';
                        prefix = '';
                        // Content already has tree character, just add padding for proper indentation
                        // Increased padding to make nested items more visually distinct and centered
                        itemContent = `<span style="padding-left: 32px; display: inline-block;">${content}</span>`;
                    } else {
                        // For top-level items, add tree prefix
                        prefix = (i === data.length - 1 ? '└── ' : '├── ');
                    }
                } else {
                    prefix = '• ';
                }
                
                output += `<div class="${itemClass}">${prefix}${itemContent}</div>`;
            }
            output += '</div>';
        } else if (defaultOptions.style === 'grid') {
            output = '<div class="command-line-grid' + styleClass + highlightClass + '">';
            const dataChuncks = arrayChunk(data, cellsPerRow);
            for (let row = 0; row < dataChuncks.length; row++) {
                output += '<div class="grid-row">';
                for (let cell = 0; cell < dataChuncks[row].length; cell++) {
                    output += `<div class="grid-cell">${dataChuncks[row][cell] || ''}</div>`;
                }
                output += '</div>';
            }
            output += '</div>';
        } else {
            output = '<table class="command-line-table' + styleClass + highlightClass + '">';
            if (defaultOptions.header && defaultOptions.header.length > 0) {
                output += '<thead><tr>';
                for (let h = 0; h < defaultOptions.header.length; h++) {
                    output += `<th>${defaultOptions.header[h]}</th>`;
                }
                output += '</tr></thead>';
            }
            output += '<tbody>';
            const dataChuncks = arrayChunk(data, cellsPerRow);
            for (let row = 0; row < dataChuncks.length; row++) {
                output += '<tr>';
                for (let cell = 0; cell < dataChuncks[row].length; cell++) {
                    output += `<td>${dataChuncks[row][cell] || ''}</td>`;
                }
                output += '</tr>';
            }
            output += '</tbody></table>';
        }

        this.output(output);
        this.commandRow.hideTime();
        Utils.addClass(this.commandRow.commandEntry, 'block');
    }

    /**
     * Output with custom style
     *
     * @param message
     * @param style - { color: '', bgColor: '', fontWeight: '', fontSize: '', className: '' }
     */
    styledOutput(message, style = {}) {
        const defaultStyle = {
            color: '',
            bgColor: '',
            fontWeight: '',
            fontSize: '',
            className: '',
            ...style
        };

        let styleAttr = '';
        if (defaultStyle.color) styleAttr += `color: ${defaultStyle.color}; `;
        if (defaultStyle.bgColor) styleAttr += `background-color: ${defaultStyle.bgColor}; `;
        if (defaultStyle.fontWeight) styleAttr += `font-weight: ${defaultStyle.fontWeight}; `;
        if (defaultStyle.fontSize) styleAttr += `font-size: ${defaultStyle.fontSize}; `;

        const className = defaultStyle.className ? ` class="${defaultStyle.className}"` : '';
        const inlineStyle = styleAttr ? ` style="${styleAttr}"` : '';

        const output = `<span${className}${inlineStyle}>${message}</span>`;
        this.output(output);
    }

    /**
     * Output JSON data in formatted way
     *
     * @param data
     * @param options - { indent: 2, colorize: true }
     */
    json(data, options = {}) {
        const defaultOptions = {
            indent: 2,
            colorize: true,
            ...options
        };

        let jsonString = '';
        try {
            jsonString = JSON.stringify(data, null, defaultOptions.indent);
        } catch (e) {
            jsonString = String(data);
        }

        if (defaultOptions.colorize) {
            jsonString = jsonString
                .replace(/(".*?")\s*:/g, '<span class="json-key">$1</span>:')
                .replace(/:\s*(".*?")/g, ': <span class="json-string">$1</span>')
                .replace(/:\s*(\d+)/g, ': <span class="json-number">$1</span>')
                .replace(/:\s*(true|false|null)/g, ': <span class="json-boolean">$1</span>');
        }

        const output = `<pre class="command-line-json">${jsonString}</pre>`;
        this.output(output);
        this.commandRow.hideTime();
        Utils.addClass(this.commandRow.commandEntry, 'block');
    }

    /**
     * Stop current execution and start a new command
     */
    stop() {
        if (this.commandRow) {
            this.commandRow.disable();
        }
        this.startNewCommand();
    }

    /**
     * Set Command line username
     *
     * @param username
     * @returns {CommandLine}
     */
    setUsername(username) {
        this.username = username;
        return this;
    }
}
